func GetProduct(ctx context.Context, id string) (*Product, error) {
    val, err := rdb.Get(ctx, "product:"+id).Bytes()
    if err == redis.Nil {
        p, err := db.QueryProduct(ctx, id)
        if err != nil {
            return nil, err
        }
        rdb.Set(ctx, "product:"+id, marshal(p), 30*time.Minute)
        return p, nil
    }
    if err != nil {
        // Redis error — no fallback, caller gets error
        return nil, fmt.Errorf("redis error: %w", err)
    }
    var p Product
    json.Unmarshal(val, &p)
    return &p, nil
}
